mapper.select:
select * from ( select ot.*, u.name as name, approver.name as approver_name, d.dept_name, r.rank_name, row_number() over (order by ot.overtime_seq desc) rn from overtime_request ot JOIN users u ON ot.users_id = u.id LEFT JOIN users approver ON ot.approver_id = approver.id JOIN departments d ON u.dept_seq = d.dept_seq JOIN rank r ON u.rank_seq = r.rank_seq
ot.status = #{status}
) where rn between #{start} and #{end}

mapper.update:
update overtime_request set 
	status = 'APPROVED', approver_id = #{approver_id}, approved_at = sysdate 
where overtime_seq = #{overtime_seq}

update overtime_request set 
	status = 'REJECTED', approver_id = #{approver_id}, approved_at = sysdate 
where overtime_seq = #{overtime_seq}
